#include<bits/stdc++.h>
using namespace std;
long long n,m,k,s,t;
vector<pair<long long,long long>> mp[100010];
long long u[100010],v[100010],w[100010];
long long diss[100010],dist[100010],dist1[100010];
void dfs(long long x,long long fa,long long dis[])
{
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=fa)
        {
            dis[v]=dis[x]+val;
            dfs(v,x,dis);
        }
    }
}
bool check(long long x)
{
    long long cnt=0;
    for(long long i=1;i<=n;i++)
    {
        cnt+=upper_bound(dist1+1,dist1+1+n,x-diss[i])-dist1-1;
    }
    for(long long i=1;i<n;i++)
    {
        if(diss[u[i]]+dist[v[i]]<=x)
        {
            cnt--;
        }
        if(diss[v[i]]+dist[u[i]]<=x)
        {
            cnt--;
        }
    }
    return cnt>m;
}
int main()
{
    scanf("%lld%lld%lld%lld%lld",&n,&m,&k,&s,&t);
    for(long long i=1;i<n;i++)
    {
        scanf("%lld%lld%lld",&u[i],&v[i],&w[i]);
        mp[u[i]].push_back({v[i],w[i]});
        mp[v[i]].push_back({u[i],w[i]});
    }
    dfs(s,-1,diss);
    dfs(t,-1,dist);
    for(long long i=1;i<=n;i++)
    {
        dist1[i]=dist[i];
    }
    sort(dist1+1,dist1+1+n);
    long long l=0,r=1e9,best=1e9;
    while(l<=r)
    {
        long long mid=(l+r)>>1;
        if(check(mid))
        {
            best=mid;
            r=mid-1;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%lld",min({diss[t],best+k,1000000000ll}));
    return 0;
}
